import{_ as a,c as i,o as t,aN as n}from"./chunks/framework.CqA5BTDU.js";const c=JSON.parse('{"title":"Nacos 集群","description":"","frontmatter":{},"headers":[],"relativePath":"07.服务注册与配置中心/05-Nacos集群.md","filePath":"07.服务注册与配置中心/05-Nacos集群.md","lastUpdated":null}'),e={name:"07.服务注册与配置中心/05-Nacos集群.md"};function h(p,s,l,d,k,r){return t(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="nacos-集群" tabindex="-1">Nacos 集群 <a class="header-anchor" href="#nacos-集群" aria-label="Permalink to &quot;Nacos 集群&quot;">​</a></h1><p>单节点 Nacos 只适合本地开发验证。真正给一组应用使用时需要集群——目的不是多开几个控制台页面，而是让配置读取、服务注册和客户端连接不因为一个 Nacos 进程挂掉就整体不可用。</p><h2 id="一、集群结构" tabindex="-1">一、集群结构 <a class="header-anchor" href="#一、集群结构" aria-label="Permalink to &quot;一、集群结构&quot;">​</a></h2><p>三节点 Nacos + 一套 MySQL 是最小的集群形态：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20access%5B%22%E5%AE%A2%E6%88%B7%E7%AB%AF%20%2F%20%E6%8E%A7%E5%88%B6%E5%8F%B0%22%5D%20--%3E%20n1%5B%22Nacos%3Cbr%2F%3E192.168.10.11%22%5D%0A%20%20%20%20access%20--%3E%20n2%5B%22Nacos%3Cbr%2F%3E192.168.10.12%22%5D%0A%20%20%20%20access%20--%3E%20n3%5B%22Nacos%3Cbr%2F%3E192.168.10.13%22%5D%0A%20%20%20%20n1%20%3C--%3E%20n2%0A%20%20%20%20n2%20%3C--%3E%20n3%0A%20%20%20%20n1%20%3C--%3E%20n3%0A%20%20%20%20n1%20--%3E%20db%5B%22MySQL%3Cbr%2F%3Enacos_config%22%5D%0A%20%20%20%20n2%20--%3E%20db%0A%20%20%20%20n3%20--%3E%20db%0A"></div><p>三个节点是比较常见的起点：两个节点出现网络分区时无法区分&quot;对方挂了&quot;和&quot;网络断了&quot;，三个节点用奇数投票不会出现平局。节点过多则通信和维护成本变高。实验里 MySQL 还是单点，所以这只是 Nacos 服务层的集群验证——生产环境中 MySQL 也要做高可用。</p><h2 id="二、集群文件-cluster-conf" tabindex="-1">二、集群文件 cluster.conf <a class="header-anchor" href="#二、集群文件-cluster-conf" aria-label="Permalink to &quot;二、集群文件 cluster.conf&quot;">​</a></h2><p><code>cluster.conf</code> 是节点互相识别的入口：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>192.168.10.11:8848</span></span>
<span class="line"><span>192.168.10.12:8848</span></span>
<span class="line"><span>192.168.10.13:8848</span></span></code></pre></div><p>三台机器内容必须完全一致。写的是 <code>8848</code>（服务端 API 端口），不是控制台 <code>8080</code>。如果某台节点没写进 <code>cluster.conf</code>，它可能自己启动但不加入集群——进程在跑，端口在监听，但集群管理页面看不到它。</p><h2 id="三、集群通信端口" tabindex="-1">三、集群通信端口 <a class="header-anchor" href="#三、集群通信端口" aria-label="Permalink to &quot;三、集群通信端口&quot;">​</a></h2><p>节点之间需要互通的端口不止 HTTP：</p><table tabindex="0"><thead><tr><th>端口</th><th>用途</th><th>互访要求</th></tr></thead><tbody><tr><td><code>8848</code></td><td>HTTP API</td><td>节点间需要互通</td></tr><tr><td><code>9848</code></td><td>客户端 gRPC</td><td>业务应用到 Nacos</td></tr><tr><td><code>9849</code></td><td>服务端 gRPC</td><td><strong>节点之间必须互通</strong></td></tr><tr><td><code>7848</code></td><td>集群一致性（Raft）通信</td><td><strong>节点之间必须互通</strong></td></tr></tbody></table><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 每台节点确认端口监听</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lntp</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> egrep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;:(8848|9848|9849|7848)\\b&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从一台测试到另一台的连通性</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.12</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8848</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.12</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 9848</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.12</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 9849</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -vz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.10.12</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7848</span></span></code></pre></div><p>本机监听正常只说明进程启动成功。防火墙、安全组、路由问题仍然可能让节点间看不见彼此。排查一个集群中&quot;只有本机&quot;的问题时，先从端口连通性查起。</p><h2 id="四、外部-mysql-的共享角色" tabindex="-1">四、外部 MySQL 的共享角色 <a class="header-anchor" href="#四、外部-mysql-的共享角色" aria-label="Permalink to &quot;四、外部 MySQL 的共享角色&quot;">​</a></h2><p>三台 Nacos 指向同一个 MySQL 数据库，目的是看到同一套配置、用户和权限数据：</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">spring.sql.init.platform</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=mysql</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">db.num</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">db.url.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=jdbc:mysql://192.168.10.11:3306/nacos_config?</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">characterEncoding</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=utf8&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">connectTimeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=10000&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">socketTimeout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=30000&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">autoReconnect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">useSSL</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=false&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">allowPublicKeyRetrieval</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=true&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">serverTimezone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=Asia/Shanghai</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">db.user.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=nacos</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">db.password.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=Nacos@123456</span></span></code></pre></div><p>Nacos 里不同类型数据的一致性机制不同：</p><table tabindex="0"><thead><tr><th>数据类型</th><th>一致性依赖</th></tr></thead><tbody><tr><td>配置数据</td><td>依赖 MySQL 保证持久化和多节点读一致</td></tr><tr><td>服务实例（临时）</td><td>依赖心跳 + 节点间 gRPC 同步 + 客户端缓存</td></tr><tr><td>权限和用户</td><td>存储在 MySQL，三节点共享同一份</td></tr></tbody></table><p>临时服务实例的一致性不是靠 MySQL，而是靠节点间的 gRPC 同步。当一个临时实例向节点 A 注册后，节点 A 会通过 gRPC 把这个变更同步给节点 B 和节点 C。如果节点间 gRPC 端口（9849）不通，各节点上看到的服务列表就可能不一致——A 节点上有这个实例，B 节点上没有。</p><p>验证配置数据一致性的直接方式——分别从三节点读同一配置，返回一致才算通过。</p><h2 id="五、集群管理页面怎么看" tabindex="-1">五、集群管理页面怎么看 <a class="header-anchor" href="#五、集群管理页面怎么看" aria-label="Permalink to &quot;五、集群管理页面怎么看&quot;">​</a></h2><p>控制台集群管理页面能看到节点列表，核心关注：</p><table tabindex="0"><thead><tr><th>字段</th><th>正常值</th></tr></thead><tbody><tr><td>节点数量</td><td>等于 <code>cluster.conf</code> 里配置的数量</td></tr><tr><td>节点状态</td><td>全部为 <code>UP</code></td></tr><tr><td>版本</td><td>三台一致</td></tr><tr><td>Raft 端口</td><td>正确</td></tr></tbody></table><p>节点状态 <code>UP</code> 表示集群视角下该节点可用。如果节点数量少了一台：先看那台的 Nacos 进程是否在跑 → <code>cluster.conf</code> 内容是否一致 → 通信端口是否互通。</p><h2 id="六、节点故障时的影响" tabindex="-1">六、节点故障时的影响 <a class="header-anchor" href="#六、节点故障时的影响" aria-label="Permalink to &quot;六、节点故障时的影响&quot;">​</a></h2><p>单个 Nacos 节点故障后，客户端能否自动切换取决于接入方式：</p><table tabindex="0"><thead><tr><th>接入方式</th><th>行为</th></tr></thead><tbody><tr><td>客户端写多个 Nacos 地址</td><td>依赖客户端 SDK 重试其他地址</td></tr><tr><td>前面放负载均衡（VIP/域名）</td><td>应用只连一个入口，负载均衡需对 Nacos 做健康检查</td></tr><tr><td>K8s 内部 Service</td><td>集群内应用通过 Service 访问，K8s 负责转发</td></tr></tbody></table><p>客户端写多个地址时，SDK 的行为通常是：连第一个地址，失败后尝试第二个。但这个切换不是瞬间的——取决于客户端的连接超时和重试间隔。如果第一个地址的机器是宕机（而不是端口拒绝连接），客户端可能要等 TCP 连接超时（几十秒）才会切到下一个地址。</p><p>负载均衡的健康检查不能只看端口通不通——端口通但 Nacos 内部接口异常时，负载均衡仍会把流量下发到故障节点。健康检查应该访问 Nacos 的实际接口，比如登录 API 或配置读取 API：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 比单纯 TCP 端口检查更可靠——验证 Nacos 内部业务是否正常</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sS</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/null</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;%{http_code}&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -X</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> POST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://192.168.10.11:8848/nacos/v3/auth/user/login&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;username=nacos&amp;password=nacos&#39;</span></span></code></pre></div><h2 id="七、升级和维护顺序" tabindex="-1">七、升级和维护顺序 <a class="header-anchor" href="#七、升级和维护顺序" aria-label="Permalink to &quot;七、升级和维护顺序&quot;">​</a></h2><p>滚动操作方式：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 停止一个节点（或从负载均衡摘除）</span></span>
<span class="line"><span>2. 确认业务客户端仍在连接其他节点（看其他节点的连接和日志）</span></span>
<span class="line"><span>3. 升级或修改该节点的配置</span></span>
<span class="line"><span>4. 启动，确认控制台状态回到 UP</span></span>
<span class="line"><span>5. 观察一段时间（配置读写、服务注册恢复正常）</span></span>
<span class="line"><span>6. 再操作下一台</span></span></code></pre></div><p>升级前备份：MySQL 数据库、<code>application.properties</code>、<code>cluster.conf</code>、systemd unit。Nacos 版本升级可能涉及配置项改名、数据库 schema 变更、API 路径变化——不能只替换二进制包。</p><p>升级前还要确认三件事：release notes 里有没有数据库 schema 变更（需要先执行升级脚本）、配置项名称有没有变化（旧配置项可能已被废弃）、API 版本是否兼容（客户端 SDK 版本和服务端版本不一定能混用）。</p><h2 id="八、常见集群异常" tabindex="-1">八、常见集群异常 <a class="header-anchor" href="#八、常见集群异常" aria-label="Permalink to &quot;八、常见集群异常&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>排查方向</th></tr></thead><tbody><tr><td>节点启动但不入集群</td><td><code>cluster.conf</code> 内容不一致、节点间端口不通</td></tr><tr><td>控制台只看到一个节点</td><td>其他节点的进程、端口、cluster.conf</td></tr><tr><td>配置发布失败</td><td>MySQL 连接、鉴权配置、数据库 schema 版本</td></tr><tr><td>某节点读到配置异常</td><td>该节点的 MySQL 连接或鉴权参数与其他节点不一致</td></tr><tr><td>服务实例频繁掉线</td><td>客户端心跳间隔、网络抖动、gRPC 端口不通</td></tr><tr><td>版本显示不一致</td><td>软链接指向不同版本目录，升级不完整</td></tr></tbody></table><p>集群排查的效率取决于是否三台一起对比——配置文件、进程参数、端口监听、日志时间点、控制台节点列表。单独看一台，很容易漏掉&quot;只有这一台配得不一样&quot;的问题。</p><p>具体做法：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 三台同时执行，输出并排对比</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> host </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.11</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.12</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 192.168.10.13</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">do</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;========== \${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">host</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">} ==========&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  ssh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${host} </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;cat /opt/nacos/conf/cluster.conf&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  ssh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${host} </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ss -lntp | egrep &#39;:(8848|9848|9849|7848)\\b&#39;&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  echo</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">done</span></span></code></pre></div><p>三台输出完全一致才算集群配置对齐。任何一行的差异都可能是异常的来源。</p>`,43)])])}const g=a(e,[["render",h]]);export{c as __pageData,g as default};
